import Foundation

func solve(nums: [Int64], queries: [[Int64]]) -> Int64 {
    let MOD = 109 + 7
    var nums = nums
    for query in queries {
        let li = query[0]
        let ri = query[1]
        let ki = query[2]
        let vi = query[3]
        var idx = li
        while idx <= ri {
            nums[idx] = (nums[idx] * vi) % MOD
            idx += ki
        }
    }
    var xor = 0
    for num in nums {
        xor ^= num
    }
    return xor
}
