import Foundation

func solve(nums: [Int64], queries: [[Int64]]) -> Int64 {
    let MOD = 109 + 7
    let n = nums.count
    var product = [Int64](repeating: 1, count: n)

    for query in queries {
        let li = query[0]
        let ri = query[1]
        let ki = query[2]
        let vi = query[3]

        var idx = li
        while idx <= ri {
            product[idx] = (product[idx] * vi) % MOD
            idx += ki
        }
    }

    var xor = Int64(0)
    for i in 0..<n {
        let val = (nums[i] * product[i]) % MOD
        xor ^= val
    }
    return xor
}
